 24→import { memo, useCallback, useEffect, useMemo, useState } from "react";
 25→import {
 26→  CustomDashboardStorage,
 27→  type CustomDashboardConfig,
 28→} from "./custom-dashboard-storage";
 29→import { PanelEditView } from "./panel-edit/panel-edit-view";
 30→import { TabManager } from "@/components/tab-manager";
 31→import {
 32→  CustomDashboardContext,
 33→  type CustomDashboardPanelActions,
 34→} from "./custom-dashboard-context";
 35→
 36→interface CustomDashboardTabProps {
 37→  dashboardId: string;
 38→  dashboardName?: string;
 39→}
 40→
 41→const CustomDashboardTabComponent = ({
 42→  dashboardId,
 43→  dashboardName,
 44→}: CustomDashboardTabProps) => {
 45→  const storage = CustomDashboardStorage.getInstance();
 46→
 47→  // Load dashboard config from storage
 48→  const [config, setConfig] = useState<CustomDashboardConfig | null>(null);
 49→  const [isEditing, setIsEditing] = useState(false);
 50→  const [editingName, setEditingName] = useState("");
 51→  const [editViewOpen, setEditViewOpen] = useState(false);
 52→  const [editingPanel, setEditingPanel] = useState<PanelDescriptor | null>(null);
 53→  const [editingPanelIndex, setEditingPanelIndex] = useState<number>(-1);
 54→
 55→  // Track the rendered dashboard key to force re-render after edits
 56→  const [dashboardKey, setDashboardKey] = useState(0);
 57→
 58→
 59→  // Load from storage on mount
 60→  useEffect(() => {
 61→    const loaded = storage.get(dashboardId);
 62→    if (loaded) {
 63→      setConfig(loaded);
 64→      setEditingName(loaded.name);
 65→    } else {
 66→      // Dashboard not found - create a new one
 67→      const newConfig = storage.createNew(dashboardName ?? "Untitled Dashboard");
 68→      // Update the ID to match
 69→      newConfig.id = dashboardId;
 70→      storage.save(newConfig);
 71→      setConfig(newConfig);
 72→      setEditingName(newConfig.name);
 73→      setIsEditing(true);
 74→    }
 75→  }, [dashboardId, dashboardName, storage]);
 76→
 77→  // Save config to storage (forces dashboard re-render for structural changes)
 78→  const saveConfig = useCallback(
 79→    (updatedConfig: CustomDashboardConfig) => {
 80→      storage.save(updatedConfig);
 81→      setConfig(updatedConfig);
 82→      setDashboardKey((k) => k + 1);
 83→    },
 84→    [storage]
 85→  );
 86→
 87→  // Handle name edit
 88→  const handleSaveName = useCallback(() => {
 89→    if (!config) return;
 90→    const trimmed = editingName.trim();
 91→    if (!trimmed) return;
 92→    const updated = { ...config, name: trimmed };
 93→    saveConfig(updated);
 94→    setIsEditing(false);
 95→
 96→    // Update tab title
 97→    TabManager.updateTabTitle(
 98→      `custom-dashboard:${dashboardId}`,
 99→      trimmed
100→    );
101→  }, [config, editingName, saveConfig, dashboardId]);
102→
103→  // Save panel (create or update)
104→  const handleSavePanel = useCallback(
105→    (panel: PanelDescriptor) => {
106→      if (!config) return;
107→
108→      if (editingPanelIndex >= 0) {
109→        // Update existing panel
110→        const updatedPanels = updatePanelAtFlatIndex(config.panels, editingPanelIndex, panel);
111→        saveConfig({ ...config, panels: updatedPanels });
112→      } else {
113→        // Add new panel to the first section
114→        const updatedPanels = addPanelToFirstSection(config.panels, panel);
115→        saveConfig({ ...config, panels: updatedPanels });
116→      }
117→      setEditingPanel(null);
118→      setEditingPanelIndex(-1);
119→      setEditViewOpen(false);
120→    },
121→    [config, editingPanelIndex, saveConfig]
122→  );
123→
124→  // Edit panel - opens full-screen edit view
125→  const handleEditPanel = useCallback(
126→    (index: number) => {
127→      if (!config) return;
128→      const panels = flattenPanels(config.panels);
129→      if (index >= 0 && index < panels.length) {
130→        setEditingPanel(panels[index]);
131→        setEditingPanelIndex(index);
132→        setEditViewOpen(true);
133→      }
134→    },
135→    [config]
136→  );
137→
138→  // Delete panel by flat index
139→  const handleDeletePanel = useCallback(
140→    (index: number) => {
141→      if (!config) return;
142→      const updatedPanels = deletePanelAtFlatIndex(config.panels, index);
